// ============================================
// AUTO-REPLY BOT — Evolution API Webhook Handler
// ============================================
// Uses require('http') — n8n sandbox has no global fetch/URL
// Handles both @s.whatsapp.net and @lid (LID) JID formats
// ============================================

const http = require('http');

// --- CONFIG ---
const EVO_HOST = 'host.docker.internal';
const EVO_PORT = 8080;
const EVO_API_KEY = 'fa67ff482194dac60c4ffa0733a83d43cc540ce9';

const AUTO_REPLY_MESSAGE = '\ud83e\udd16 *PESAN OTOMATIS*\n\nTerima kasih telah menghubungi kami.\nNomor ini adalah bot otomatis untuk pengiriman invoice.\n\nUntuk informasi lebih lanjut, silakan hubungi:\n\ud83d\udcde Customer Service kami\n\n\u2014 _PT Global Teknik Multi Guna_';
// --- END CONFIG ---

function httpReq(path, method, headers, body) {
  return new Promise((resolve, reject) => {
    const opts = {
      hostname: EVO_HOST, port: EVO_PORT,
      path: path, method: method || 'GET',
      headers: headers || {}
    };
    const req = http.request(opts, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        let json;
        try { json = JSON.parse(data); } catch (e) { json = {}; }
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, statusCode: res.statusCode, statusText: res.statusMessage, data: json });
      });
    });
    req.on('error', reject);
    if (body) req.write(typeof body === 'string' ? body : JSON.stringify(body));
    req.end();
  });
}

const raw = $input.first().json;
const body = raw.body || raw;

const event = body.event || '';
const instance = body.instance || '';
const data = body.data || body;

if (event && event !== 'messages.upsert') {
  return [{ json: { skipped: true, reason: 'Not a message event', event } }];
}

let remoteJid = '';
let fromMe = false;
let messageText = '';
let pushName = '';

if (data.key) {
  remoteJid = data.key.remoteJid || '';
  fromMe = data.key.fromMe || false;
  pushName = data.pushName || '';
  messageText = (data.message && data.message.conversation) || (data.message && data.message.extendedTextMessage && data.message.extendedTextMessage.text) || '';
} else if (Array.isArray(data) && data.length > 0) {
  const msg = data[0];
  remoteJid = (msg.key && msg.key.remoteJid) || '';
  fromMe = (msg.key && msg.key.fromMe) || false;
  pushName = msg.pushName || '';
  messageText = (msg.message && msg.message.conversation) || (msg.message && msg.message.extendedTextMessage && msg.message.extendedTextMessage.text) || '';
} else if (data.message && data.message.key) {
  remoteJid = data.message.key.remoteJid || '';
  fromMe = data.message.key.fromMe || false;
  pushName = data.message.pushName || '';
}

if (fromMe) {
  return [{ json: { skipped: true, reason: 'Message from self' } }];
}
if (!remoteJid || remoteJid.indexOf('@g.us') !== -1 || remoteJid.indexOf('@broadcast') !== -1 || remoteJid === 'status@broadcast') {
  return [{ json: { skipped: true, reason: 'Group/broadcast/invalid', remoteJid } }];
}

// Handle both JID formats:
// - Old: 6285156541820@s.whatsapp.net → use phone number
// - New (LID): 24219438022844@lid → use full remoteJid as-is
const isLid = remoteJid.indexOf('@lid') !== -1;
const sendTo = isLid ? remoteJid : remoteJid.replace('@s.whatsapp.net', '');

try {
  const res = await httpReq(
    '/message/sendText/' + instance,
    'POST',
    { 'Content-Type': 'application/json', 'apikey': EVO_API_KEY },
    JSON.stringify({ number: sendTo, text: AUTO_REPLY_MESSAGE })
  );

  if (!res.ok) {
    return [{ json: { success: false, error: JSON.stringify(res.data) || res.statusText, status: res.statusCode, sendTo: sendTo, remoteJid: remoteJid, isLid: isLid, instance: instance } }];
  }

  return [{ json: {
    success: true,
    repliedTo: sendTo,
    remoteJid: remoteJid,
    isLid: isLid,
    pushName: pushName,
    instance: instance,
    originalMessage: (messageText || '').substring(0, 100)
  }}];
} catch (err) {
  return [{ json: { success: false, error: String(err.message || err), sendTo: sendTo, remoteJid: remoteJid, instance: instance } }];
}
